#include <iostream>
#include <string>

// --- Macros ---

#define PI 3.14159
#define MAX(a, b) ((a) > (b) ? (a) : (b))
#define SQUARE(x) ((x) * (x))
#define LOG(msg) std::cout << "[LOG] " << msg << std::endl

// --- Conditional compilation ---

#define DEBUG 1
#define GAME_VERSION 2

#if GAME_VERSION >= 2
    #define FEATURE_SAVING 1
#else
    #define FEATURE_SAVING 0
#endif

// --- Debug macros ---

#ifdef DEBUG
    #define DEBUG_LOG(msg) std::cout << "🔍 DEBUG: " << msg << std::endl
#else
    #define DEBUG_LOG(msg)
#endif

// --- Stringification ---

#define STRINGIFY(x) #x
#define CONCAT(a, b) a##b

// --- Multi-line macro ---

#define PRINT_ARRAY(arr, size) \
    do { \
        std::cout << #arr << ": "; \
        for (int i = 0; i < size; i++) { \
            std::cout << arr[i] << " "; \
        } \
        std::cout << std::endl; \
    } while (0)

// --- Game configuration macros ---

#define MAX_PLAYERS 10
#define MAX_LEVEL 99
#define DEFAULT_HEALTH 100
#define MAX_INVENTORY 20

// --- Conditional compilation for platform ---

// #define WINDOWS 1
// #define LINUX 1

void platformSpecificCode() {
    #ifdef WINDOWS
        std::cout << "Running on Windows" << std::endl;
    #elif defined(LINUX)
        std::cout << "Running on Linux" << std::endl;
    #else
        std::cout << "Unknown platform" << std::endl;
    #endif
}

int main() {
    std::cout << "=== Preprocessor Directives & Macros ===" << std::endl;

    // 1. Constants
    std::cout << "\n--- Constants ---" << std::endl;
    std::cout << "PI = " << PI << std::endl;
    std::cout << "MAX_PLAYERS = " << MAX_PLAYERS << std::endl;
    std::cout << "MAX_LEVEL = " << MAX_LEVEL << std::endl;

    // 2. Function-like macros
    std::cout << "\n--- Function-like Macros ---" << std::endl;
    std::cout << "MAX(10, 20) = " << MAX(10, 20) << std::endl;
    std::cout << "SQUARE(5) = " << SQUARE(5) << std::endl;

    int x = 10, y = 5;
    std::cout << "MAX(x++, y) = " << MAX(x++, y) << std::endl;

    // 3. Logging macros
    std::cout << "\n--- Logging ---" << std::endl;
    LOG("Game started");
    LOG("Player loaded");

    // 4. Debug logging
    std::cout << "\n--- Debug Logging ---" << std::endl;
    DEBUG_LOG("Initializing game...");
    DEBUG_LOG("Player health: 100");

    // 5. Stringification
    std::cout << "\n--- Stringification ---" << std::endl;
    std::cout << "STRINGIFY(Hello World) = " << STRINGIFY(Hello World) << std::endl;

    int value = 42;
    int CONCAT(my, Value) = value;
    std::cout << "myValue = " << myValue << std::endl;

    // 6. Multi-line macro
    std::cout << "\n--- Multi-line Macro ---" << std::endl;
    int arr[5] = {10, 20, 30, 40, 50};
    PRINT_ARRAY(arr, 5);

    // 7. Conditional compilation
    std::cout << "\n--- Conditional Compilation ---" << std::endl;
    std::cout << "GAME_VERSION: " << GAME_VERSION << std::endl;
    std::cout << "FEATURE_SAVING: " << FEATURE_SAVING << std::endl;

    platformSpecificCode();

    // 8. Game configuration
    std::cout << "\n--- Game Configuration ---" << std::endl;
    std::cout << "Max Players: " << MAX_PLAYERS << std::endl;
    std::cout << "Max Level: " << MAX_LEVEL << std::endl;
    std::cout << "Default Health: " << DEFAULT_HEALTH << std::endl;
    std::cout << "Max Inventory: " << MAX_INVENTORY << std::endl;

    std::cout << "\n--- Macro Best Practices ---" << std::endl;
    std::cout << "✅ Use constexpr or const instead of macros when possible" << std::endl;
    std::cout << "✅ Use inline functions instead of function-like macros" << std::endl;
    std::cout << "✅ Use #ifdef for platform-specific code" << std::endl;
    std::cout << "✅ Use macros only when necessary" << std::endl;

    return 0;
}

