phase3.solution:
#include <iostream>
#include <string>

#define MAX(a, b) ((a) > (b) ? (a) : (b))
#define MIN(a, b) ((a) < (b) ? (a) : (b))
#define SAFE_DIV(a, b) ((b) != 0 ? (a) / (b) : 0)

#define DEBUG 1
#define GAME_VERSION 3

int main() {
    std::cout << "=== Preprocessor Macros ===" << std::endl;

    std::cout << "\n--- MAX and MIN ---" << std::endl;
    std::cout << "MAX(10, 20) = " << MAX(10, 20) << std::endl;
    std::cout << "MAX(3 + 1, 5) = " << MAX(3 + 1, 5) << std::endl;
    std::cout << "MIN(10, 20) = " << MIN(10, 20) << std::endl;

    std::cout << "\n--- SAFE_DIV ---" << std::endl;
    std::cout << "SAFE_DIV(10, 2) = " << SAFE_DIV(10, 2) << std::endl;
    std::cout << "SAFE_DIV(10, 0) = " << SAFE_DIV(10, 0) << std::endl;

    #ifdef DEBUG
        std::cout << "\n--- Debug Messages ---" << std::endl;
        std::cout << "🔍 Debug mode active!" << std::endl;
        std::cout << "🔍 MAX test passed: " << MAX(5, 10) << std::endl;
    #endif

    #if GAME_VERSION >= 3
        std::cout << "\n--- Feature Status ---" << std::endl;
        std::cout << "✅ Advanced features enabled!" << std::endl;
        std::cout << "✅ New game mode available" << std::endl;
    #else
        std::cout << "Basic features only" << std::endl;
    #endif

    std::cout << "\n✅ Done!" << std::endl;

    return 0;
}
